// ─── Helper: build the reference context block for Gemini prompts ─────────────
export const buildReferenceContext = (): string => {
  const populated = MOC_REFERENCES.filter(r => !r.base64.startsWith("REPLACE_"));
  if (populated.length === 0) return "";
  return `
### MOC VISUAL REFERENCES (${populated.length} images provided above)
The images sent before this text are REFERENCE SCREENSHOTS of Mob Control's actual visual style.
Use them ONLY as a visual dictionary — do NOT analyze or extract DNA from them.
They teach you:
- What the Foggy Forest biome looks like (grey mist, dark pine trees, grey road — NOT snow)
- What the Desert biome looks like (tan sand, bright sun, blue sky)
- What death gates look like (red rectangle with skull-and-crossbones)
- What multiplication gates look like (various colors: blue, orange, pink, purple)
- What addition gates look like (blue frames with +1, +2 etc.)
- What specific champions look like (Captain Kaboom = small skeleton pirate with mushroom hat)
- What the yellow normie boss looks like
- What 'almost win' and 'almost fail' emotional moments look like

After reviewing these references, analyze ONLY the video that follows.`;
};

// ─── Helper: build inline data parts for Gemini API ──────────────────────────
export const buildReferenceParts = (): any[] => {
  const populated = MOC_REFERENCES.filter(r => !r.base64.startsWith("REPLACE_"));
  if (populated.length === 0) return [];
  
  const parts: any[] = [{ text: "### MOC VISUAL REFERENCE IMAGES (use as visual dictionary only — do NOT analyze these):" }];
  populated.forEach(ref => {
    parts.push({ text: `Reference [${ref.category.toUpperCase()}]: ${ref.label}` });
    parts.push({ inlineData: { mimeType: "image/jpeg", data: ref.base64 } });
  });
  return parts;
};
